1	/**
2	 * Addon installation and activation management
3	 */
4	
5	import * as fs from 'fs';
6	import * as path from 'path';
7	import * as os from 'os';
8	import * as readline from 'readline';
9	import { getLocalPaths, ADDON_PACKAGE_NAME, ADDON_DIR_NAME } from './paths';
10	import { isLocalRunning, stopLocal, restartLocal } from './process';
11	import { detectPlatform, getPlatformDisplayName } from './platform';
12	import { downloadAddon, formatBytes } from './downloader';
13	import { extractTarball, verifyExtractedAddon } from './extractor';
14	import { getCurrentVersion } from '../utils/version';
15	
16	/**
17	 * Get the addon installation path
18	 */
19	export function getAddonPath(): string {
20	  const paths = getLocalPaths();
21	  return path.join(paths.addonsDir, ADDON_DIR_NAME);
22	}
23	
24	/**
25	 * Check if the addon is installed in Local's addons directory
26	 */
27	export function isAddonInstalled(): boolean {
28	  const addonPath = getAddonPath();
29	
30	  // Check for directory or symlink
31	  try {
32	    const stat = fs.lstatSync(addonPath);
33	    return stat.isDirectory() || stat.isSymbolicLink();
34	  } catch {
35	    return false;
36	  }
37	}
38	
39	/**
40	 * Get installed addon version from package.json
41	 * Returns null if addon not installed or version can't be read
42	 */
43	export function getInstalledAddonVersion(): string | null {
44	  const addonPath = getAddonPath();
45	  const packageJsonPath = path.join(addonPath, 'package.json');
46	
47	  try {
48	    if (!fs.existsSync(packageJsonPath)) {
49	      return null;
50	    }
51	
52	    const pkg = JSON.parse(fs.readFileSync(packageJsonPath, 'utf-8'));
53	    return pkg.version || null;
54	  } catch {
55	    return null;
56	  }
57	}
58	
59	/**
60	 * Check if installed addon is a development symlink
61	 */
62	export function isDevAddon(): boolean {
63	  const addonPath = getAddonPath();
64	
65	  try {
66	    const stat = fs.lstatSync(addonPath);
67	    return stat.isSymbolicLink();
68	  } catch {
69	    return false;
70	  }
71	}
72	
73	/**
74	 * Check if the addon is activated in enabled-addons.json
75	 */
76	export function isAddonActivated(): boolean {
77	  const paths = getLocalPaths();
78	
79	  try {
80	    if (!fs.existsSync(paths.enabledAddonsFile)) {
81	      return false;
82	    }
83	
84	    const content = fs.readFileSync(paths.enabledAddonsFile, 'utf-8');
85	    const enabledAddons: Record<string, boolean> = JSON.parse(content);
86	
87	    return enabledAddons[ADDON_PACKAGE_NAME] === true;
88	  } catch {
89	    return false;
90	  }
91	}
92	
93	/**
94	 * Activate the addon by modifying enabled-addons.json
95	 * Returns true if restart is needed (addon was just activated)
96	 */
97	export function activateAddon(): boolean {
98	  const paths = getLocalPaths();
99	
100	  try {
101	    let enabledAddons: Record<string, boolean> = {};
102	
103	    if (fs.existsSync(paths.enabledAddonsFile)) {
104	      const content = fs.readFileSync(paths.enabledAddonsFile, 'utf-8');
105	      enabledAddons = JSON.parse(content);
106	    }
107	
108	    // Check if already activated
109	    if (enabledAddons[ADDON_PACKAGE_NAME] === true) {
110	      return false; // Already active, no restart needed
111	    }
112	
113	    // Activate the addon
114	    enabledAddons[ADDON_PACKAGE_NAME] = true;
115	    fs.writeFileSync(paths.enabledAddonsFile, JSON.stringify(enabledAddons, null, 2));
116	
117	    // Verify write succeeded
118	    const verifyContent = fs.readFileSync(paths.enabledAddonsFile, 'utf-8');
119	    const verified = JSON.parse(verifyContent);
120	    if (verified[ADDON_PACKAGE_NAME] !== true) {
121	      console.error('Warning: Failed to persist addon activation');
122	      return false;
123	    }
124	
125	    return true; // Restart needed
126	  } catch (error: unknown) {
127	    const message = error instanceof Error ? error.message : String(error);
128	    console.error(`Failed to activate addon: ${message}`);
129	    console.error(`File: ${paths.enabledAddonsFile}`);
130	    return false;
131	  }
132	}
133	
134	/**
135	 * Copy a directory recursively
136	 */
137	function copyDirSync(src: string, dest: string): void {
138	  fs.mkdirSync(dest, { recursive: true });
139	
140	  const entries = fs.readdirSync(src, { withFileTypes: true });
141	
142	  for (const entry of entries) {
143	    const srcPath = path.join(src, entry.name);
144	    const destPath = path.join(dest, entry.name);
145	
146	    if (entry.isDirectory()) {
147	      copyDirSync(srcPath, destPath);
148	    } else {
149	      fs.copyFileSync(srcPath, destPath);
150	    }
151	  }
152	}
153	
154	/**
155	 * Find the bundled addon path (included in npm package)
156	 * Located at addon-dist/ relative to the CLI package root
157	 */
158	function findBundledAddonPath(): string | null {
159	  // From lib/cli/bootstrap/ -> addon-dist/
160	  const bundledPath = path.resolve(__dirname, '..', '..', '..', 'addon-dist');
161	
162	  if (fs.existsSync(path.join(bundledPath, 'package.json'))) {
163	    return bundledPath;
164	  }
165	
166	  return null;
167	}
168	
169	/**
170	 * Find the local development addon path (for dev mode)
171	 * Only activates when running from a git repo — never matches an installed npm package.
172	 */
173	function findDevAddonPath(): string | null {
174	  // From lib/cli/bootstrap/ (compiled) or src/cli/bootstrap/ (ts-node), go up to project root
175	  const projectRoot = path.resolve(__dirname, '..', '..', '..');
176	
177	  // Require .git to exist — installed npm packages never have .git
178	  if (!fs.existsSync(path.join(projectRoot, '.git'))) {
179	    return null;
180	  }
181	
182	  // Verify this looks like the Nexus AI dev repo
183	  const srcMain = path.join(projectRoot, 'src', 'main', 'index.ts');
184	  if (!fs.existsSync(srcMain)) {
185	    return null;
186	  }
187	
188	  return projectRoot;
189	}
190	
191	/**
192	 * Prompt user for auto-download confirmation
193	 */
194	async function promptAutoDownload(platformName: string): Promise<boolean> {
195	  console.log('');
196	  console.log('Nexus AI addon not found.');
197	  console.log(`Detected platform: ${platformName}`);
198	  console.log('');
199	
200	  const rl = readline.createInterface({
201	    input: process.stdin,
202	    output: process.stdout
203	  });
204	
205	  return new Promise<boolean>((resolve) => {
206	    rl.question('Download and install addon from releases.elasticapi.io? (Y/n) ', (answer) => {
207	      rl.close();
208	      resolve(answer.toLowerCase() !== 'n');
209	    });
210	  });
211	}
212	
213	/**
214	 * Auto-download addon from releases.elasticapi.io
215	 */
216	async function autoDownloadAddon(
217	  options: {
218	    onStatus?: (status: string) => void;
219	  } = {}
220	): Promise<{ success: boolean; error?: string }> {
221	  const log = options.onStatus || (() => {});
222	
223	  try {
224	    // Detect platform
225	    const platform = detectPlatform();
226	    const platformName = getPlatformDisplayName(platform);
227	
228	    // Prompt user for confirmation
229	    const confirmed = await promptAutoDownload(platformName);
230	
231	    if (!confirmed) {
232	      console.log('');
233	      console.log('Skipping auto-install. To install manually:');
234	      console.log('1. Download the addon for your platform from:');
235	      console.log('   https://releases.elasticapi.io/nexus-ai/latest.json');
236	      console.log(`2. Download: https://releases.elasticapi.io/nexus-ai/v{version}/${platform.assetName}`);
237	      console.log('3. Extract to your Local addons directory');
238	      console.log('4. Restart Local');
239	      console.log('');
240	
241	      return { success: false, error: 'User cancelled auto-install' };
242	    }
243	
244	    // Download to temp directory
245	    const tmpPath = path.join(os.tmpdir(), 'nexus-ai-addon.tgz');
246	    const version = getCurrentVersion();
247	    log(`Downloading ${platform.assetName}...`);
248	
249	    await downloadAddon({
250	      assetName: platform.assetName,
251	      version,
252	      destPath: tmpPath,
253	      onProgress: (percent, downloaded, total) => {
254	        if (total > 0) {
255	          log(`Downloading... ${percent}% (${formatBytes(downloaded)} / ${formatBytes(total)})`);
256	        } else {
257	          log(`Downloading... ${formatBytes(downloaded)}`);
258	        }
259	      },
260	    });
261	
262	    log('Download complete. Installing...');
263	
264	    // Extract to addon directory
265	    const addonPath = getAddonPath();
266	    await extractTarball({
267	      tarPath: tmpPath,
268	      destDir: addonPath,
269	      stripComponents: 0  // Tarball contents are at root level
270	    });
271	
272	    // Verify installation
273	    if (!verifyExtractedAddon(addonPath)) {
274	      fs.rmSync(addonPath, { recursive: true, force: true });
275	      throw new Error('Extracted addon is invalid. Installation failed.');
276	    }
277	
278	    // Clean up temp file
279	    try {
280	      fs.unlinkSync(tmpPath);
281	    } catch {
282	      // Non-fatal: temp file cleanup failure
283	    }
284	
285	    log('✓ Addon installed successfully!');
286	    console.log('');
287	
288	    // Auto-restart Local if running, otherwise prompt to start
289	    const running = await isLocalRunning();
290	    if (running) {
291	      console.log('Restarting Local to load addon...');
292	      await restartLocal();
293	      console.log('\x1b[32m✓ Local restarted\x1b[0m');
294	    } else {
295	      console.log('Start Local to use the addon.');
296	    }
297	    console.log('');
298	
299	    return { success: true };
300	  } catch (error: any) {
301	    // Clean up on error
302	    const addonPath = getAddonPath();
303	    try {
304	      if (fs.existsSync(addonPath)) {
305	        fs.rmSync(addonPath, { recursive: true, force: true });
306	      }
307	    } catch {
308	      // Ignore cleanup errors
309	    }
310	
311	    console.error('');
312	    console.error('Auto-install failed:', error.message);
313	    console.error('');
314	    console.error('Please install manually:');
315	    console.error('https://releases.elasticapi.io/nexus-ai/latest.json');
316	    console.error('');
317	
318	    return { success: false, error: error.message };
319	  }
320	}
321	
322	/**
323	 * Install the addon from bundled package or create dev symlink
324	 */
325	export async function installAddon(
326	  options: {
327	    onStatus?: (status: string) => void;
328	  } = {}
329	): Promise<{ success: boolean; error?: string; needsRestart: boolean }> {
330	  const log = options.onStatus || (() => {});
331	  const paths = getLocalPaths();
332	  const addonPath = getAddonPath();
333	
334	  try {
335	    // Ensure addons directory exists
336	    if (!fs.existsSync(paths.addonsDir)) {
337	      fs.mkdirSync(paths.addonsDir, { recursive: true });
338	    }
339	
340	    // Try bundled addon first (production - included in npm package)
341	    const bundledAddonPath = findBundledAddonPath();
342	
343	    if (bundledAddonPath) {
344	      log('Installing bundled addon...');
345	
346	      // Copy bundled addon to Local's addons directory
347	      // Dependencies are pre-installed in addon-dist, no npm install needed
348	      copyDirSync(bundledAddonPath, addonPath);
349	
350	      log('Addon installed successfully.');
351	    } else {
352	      // Try development mode - create symlink to local addon in monorepo
353	      const devAddonPath = findDevAddonPath();
354	
355	      if (devAddonPath) {
356	        log('Using development addon (symlink)...');
357	
358	        fs.symlinkSync(devAddonPath, addonPath);
359	        log(`Created symlink: ${addonPath} -> ${devAddonPath}`);
360	      } else {
361	        // Try auto-download from releases.elasticapi.io
362	        log('Bundled addon not found. Attempting auto-download...');
363	
364	        const downloadResult = await autoDownloadAddon({ onStatus: log });
365	
366	        if (!downloadResult.success) {
367	          throw new Error(
368	            downloadResult.error || 'Addon not found. Please reinstall the CLI package: npm install -g local-addon-nexus-ai'
369	          );
370	        }
371	      }
372	    }
373	
374	    // Activate the addon
375	    const needsRestart = activateAddon();
376	
377	    return { success: true, needsRestart };
378	  } catch (error: any) {
379	    return {
380	      success: false,
381	      error: error.message || 'Failed to install addon',
382	      needsRestart: false,
383	    };
384	  }
385	}
386	
387	/**
388	 * Prompt user for addon update confirmation
389	 */
390	async function promptAddonUpdate(cliVersion: string, addonVersion: string): Promise<boolean> {
391	  console.log('');
392	  console.log(`\x1b[33mAddon version mismatch detected:\x1b[0m`);
393	  console.log(`  CLI:   ${cliVersion}`);
394	  console.log(`  Addon: ${addonVersion}`);
395	  console.log('');
396	
397	  const rl = readline.createInterface({
398	    input: process.stdin,
399	    output: process.stdout
400	  });
401	
402	  return new Promise<boolean>((resolve) => {
403	    rl.question('Download updated addon to match CLI version? (Y/n) ', (answer) => {
404	      rl.close();
405	      resolve(answer.toLowerCase() !== 'n');
406	    });
407	  });
408	}
409	
410	/**
411	 * Update addon to match CLI version
412	 */
413	async function updateAddon(
414	  options: {
415	    onStatus?: (status: string) => void;
416	  } = {}
417	): Promise<{ success: boolean; error?: string }> {
418	  const log = options.onStatus || (() => {});
419	  const addonPath = getAddonPath();
420	
421	  try {
422	    // Backup existing addon
423	    const backupPath = `${addonPath}.backup-${Date.now()}`;
424	    log(`Backing up current addon to ${path.basename(backupPath)}...`);
425	
426	    try {
427	      fs.renameSync(addonPath, backupPath);
428	    } catch (error: any) {
429	      throw new Error(`Failed to backup addon: ${error.message}`);
430	    }
431	
432	    // Download new version
433	    const downloadResult = await autoDownloadAddon({ onStatus: log });
434	
435	    if (!downloadResult.success) {
436	      // Restore backup on failure
437	      log('Download failed. Restoring backup...');
438	      try {
439	        if (fs.existsSync(addonPath)) {
440	          fs.rmSync(addonPath, { recursive: true, force: true });
441	        }
